"""Ashby scraper for the HaxJobs discovery pipeline."""

from __future__ import annotations

import argparse
import json
import sys
import time
import urllib.error
import urllib.request
from typing import Any

from haxjobs.db.schema import init
from haxjobs.db.discovered_jobs import insert_discovered_job
from haxjobs.discovery.normalize import normalize_job
from haxjobs.discovery.profile_search import job_matches_profile, parse_cli_search_terms
from haxjobs.discovery.scrapers.greenhouse import extract_jd_text
from haxjobs.config import DISCOVERY_CONFIG

ASHBY_GRAPHQL_URL = "https://jobs.ashbyhq.com/api/non-user-graphql?op={operation}"
REQUEST_TIMEOUT_SECONDS = 30
USER_AGENT = "HaxJobs Ashby Scraper/1.0"

JOB_BOARD_QUERY = """
query ApiJobBoardWithTeams($organizationHostedJobsPageName: String!) {
  jobBoard: jobBoardWithTeams(organizationHostedJobsPageName: $organizationHostedJobsPageName) {
    jobPostings {
      id
      title
      locationName
      employmentType
      teamId
      secondaryLocations { locationName }
    }
  }
}
"""

JOB_POSTING_QUERY = """
query ApiJobPosting($organizationHostedJobsPageName: String!, $jobPostingId: String!) {
  jobPosting(organizationHostedJobsPageName: $organizationHostedJobsPageName, jobPostingId: $jobPostingId) {
    id
    title
    locationName
    employmentType
    descriptionHtml
  }
}
"""


def post_graphql(company: str, operation: str, query: str, variables: dict[str, Any]) -> dict[str, Any]:
    """POST one Ashby non-user GraphQL request."""
    payload = json.dumps({
        "operationName": operation,
        "variables": variables,
        "query": query,
    }).encode("utf-8")
    request = urllib.request.Request(
        ASHBY_GRAPHQL_URL.format(operation=operation),
        data=payload,
        headers={
            "User-Agent": USER_AGENT,
            "Content-Type": "application/json",
            "Referer": f"https://jobs.ashbyhq.com/{company}",
        },
